AFTER UPDATE OF player_name ON player 
FOR EACH ROW 
EXECUTE PROCEDURE log_player_name_changes()

CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(key bigint)
RETURNS boolean AS $$
BEGIN
    -- Set lock timeout to 1 second for this transaction
    SET LOCAL lock_timeout = '1s';

    BEGIN
        PERFORM pg_advisory_xact_lock(key);
        RETURN true;
    EXCEPTION 
        WHEN lock_not_available THEN
            RETURN false;
        WHEN OTHERS THEN
            RETURN false;
    END;
END;
$$ LANGUAGE plpgsql

