CREATE OR REPLACE FUNCTION calculate_loan_status() 
RETURNS SETOF loan_last
AS $$
DECLARE
    rec loan_last%ROWTYPE;
BEGIN
    -- Create temp table
    CREATE TEMP TABLE IF NOT EXISTS temp_table (loan_id bigint, status text);

    -- Clear it if it exists from previous calls in same session
    TRUNCATE temp_table;

    -- Insert data
    INSERT INTO temp_table 
    SELECT loan_id, status FROM loan_first WHERE status = 'A';

    -- Insert into permanent table
    INSERT INTO loan_last SELECT loan_id, status FROM temp_table;

    -- Return results
    FOR rec IN SELECT loan_id, status FROM temp_table LOOP
        RETURN NEXT rec;
    END LOOP;

    RETURN;
END;
$$ LANGUAGE plpgsql

-- Simplest working solution

-- 1. Unique index for condition 1: consistent scores for same match-team
CREATE UNIQUE INDEX idx_match_team_score_unique ON match_results (match_id, team_id, score);

-- 2. For condition 2, use a separate table to track unique pairs and their scores
CREATE TABLE unique_match_team_scores (
    score integer PRIMARY KEY,
    match_id integer,
    team_id integer,
    UNIQUE (match_id, team_id)
);

-- 3. Trigger to maintain this table
CREATE OR REPLACE FUNCTION maintain_unique_scores()
RETURNS TRIGGER AS $$
DECLARE
    pair_count integer;
BEGIN
    -- Get count for this pair after operation
    SELECT COUNT(*) INTO pair_count
    FROM match_results
    WHERE match_id = NEW.match_id AND team_id = NEW.team_id;

    IF TG_OP = 'INSERT' THEN
        pair_count := pair_count + 1; -- Include the new row
    END IF;

    IF pair_count = 1 THEN
        -- This is or will be a unique pair, try to register it
        BEGIN
            INSERT INTO unique_match_team_scores (score, match_id, team_id)
            VALUES (NEW.score, NEW.match_id, NEW.team_id);
        EXCEPTION WHEN unique_violation THEN
            RAISE EXCEPTION 'Score % is already used by another unique match-team pair', NEW.score;
        END;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trigger_maintain_unique_scores
BEFORE INSERT ON match_results
FOR EACH ROW EXECUTE FUNCTION maintain_unique_scores()

