CREATE EVENT delete_extra_common_cards
ON SCHEDULE EVERY 1 MONTH
DO
BEGIN
    DECLARE card_count INT;
    DECLARE delete_count INT;
    SET delete_count = 0;

    SELECT COUNT(*) INTO card_count FROM cards WHERE rarity = 'common';

    IF card_count > 100 THEN
        SET delete_count = card_count - 100;
        SET @sql = CONCAT('DELETE FROM cards WHERE rarity = ''common'' ORDER BY id LIMIT ', delete_count);
        PREPARE stmt FROM @sql;
        EXECUTE stmt;
        DEALLOCATE PREPARE stmt;
    END IF;
