);

-- Create function to validate BusinessCategoryID
CREATE OR ALTER FUNCTION dbo.fn_IsValidBusinessCategory(@CategoryID INT)
RETURNS BIT
AS
BEGIN
    DECLARE @Result BIT;

    SELECT @Result = CASE 
        WHEN EXISTS (
            SELECT 1 
            FROM EventCategories 
            WHERE ID = @CategoryID 
            AND IsBusinessCategory = 1
        ) THEN 1
        ELSE 0
    END;

    RETURN @Result;
END;

-- Create BusinessCategories table with check constraint
CREATE TABLE [dbo].[BusinessCategories](
    [ID] [int] IDENTITY(1,1) NOT NULL PRIMARY KEY,
    [BusinessCategoryID] [INT] NOT NULL,
    CONSTRAINT CHK_BusinessCategoryID CHECK (dbo.fn_IsValidBusinessCategory(BusinessCategoryID) = 1)
);

