DECLARE
    TYPE t_match_id IS TABLE OF NUMBER;
    TYPE t_match_date IS TABLE OF DATE;
    TYPE t_goals IS TABLE OF NUMBER;
    TYPE t_team_name IS TABLE OF NCLOB;
    TYPE t_league_name IS TABLE OF NVARCHAR2(512);

    v_match_id t_match_id;
    v_match_date t_match_date;
    v_home_team_goals t_goals;
    v_away_team_goals t_goals;
    v_home_team_name t_team_name;
    v_away_team_name t_team_name;
    v_league_name t_league_name;
BEGIN
    SELECT "Match"."id",
           "Match"."date",
           "Match"."home_team_goal",
           "Match"."away_team_goal",
           "HomeTeam"."team_long_name",
           "AwayTeam"."team_long_name",
           "League"."name"
    BULK COLLECT INTO v_match_id, v_match_date, v_home_team_goals, 
                      v_away_team_goals, v_home_team_name, v_away_team_name, v_league_name
    FROM "Match"
    INNER JOIN "Team" "HomeTeam" ON "Match"."home_team_api_id" = "HomeTeam"."team_api_id"
    INNER JOIN "Team" "AwayTeam" ON "Match"."away_team_api_id" = "AwayTeam"."team_api_id"
    INNER JOIN "League" ON "Match"."league_id" = "League"."id"
    ORDER BY "Match"."date";

    -- Process collections here
    -- For example: FOR i IN 1..v_match_id.COUNT LOOP ... END LOOP;
END

DECLARE
    v_year NUMBER := 2008;
    v_week VARCHAR2(2) := '47';
    v_home_team_wins NUMBER;
    v_away_team_wins NUMBER;
    v_draws NUMBER;
    v_total_matches NUMBER;
BEGIN
    SELECT SUM(CASE WHEN "home_team_goal" > "away_team_goal" THEN 1 ELSE 0 END),
           SUM(CASE WHEN "home_team_goal" < "away_team_goal" THEN 1 ELSE 0 END),
           SUM(CASE WHEN "home_team_goal" = "away_team_goal" THEN 1 ELSE 0 END),
           COUNT(*)
    INTO v_home_team_wins, v_away_team_wins, v_draws, v_total_matches
    FROM "Match"
    WHERE EXTRACT(YEAR FROM "date") = v_year
      AND TO_CHAR("date", 'IW') = v_week;

    DBMS_OUTPUT.PUT_LINE('Year: ' || v_year || ', Week: ' || v_week || 
                         ', Home Wins: ' || v_home_team_wins || 
                         ', Away Wins: ' || v_away_team_wins ||
                         ', Draws: ' || v_draws ||
                         ', Total: ' || v_total_matches);
END
